// Đọc kết quả Google Sheets + merge trigger data
const trigger = $('When chat message received').first().json;
const rows = $input.all();

// Mặc định rỗng nếu không có row khớp
let prev = {
  last_user_msg: '',
  last_intent: '',
  last_brand: '',
  last_model: '',
  last_ai_reply: ''
};

// Nếu googleSheets trả về row có sessionId thật → dùng làm prev
if (rows.length && rows[0].json && rows[0].json.sessionId) {
  prev = {
    last_user_msg: rows[0].json.last_user_msg || '',
    last_intent:   rows[0].json.last_intent   || '',
    last_brand:    rows[0].json.last_brand    || '',
    last_model:    rows[0].json.last_model    || '',
    last_ai_reply: rows[0].json.last_ai_reply || ''
  };
}

return [{
  json: {
    ...trigger,
    _prev: prev
  }
}];

// Capture AI reply để lưu vào sheet
const reply = $input.first().json.output || '';
return [{
  json: {
    output: reply,                              // giữ nguyên cho chat trigger
    _ai_reply_short: reply.slice(0, 300)        // cap 300 chars để tránh bloat sheet
  }
}];

// Lấy reply gốc từ node capture_reply (cách 2 node phía trước)
// vì gs_update_reply đã đổi shape output thành row của Google Sheets
const aiReply = $('capture_reply').first().json.output || '';

// Emit lại theo format chat trigger hiểu
return [{
  json: {
    output: aiReply
  }
}];
